module mux4x32 (
    input [31:0] in0,
    input [31:0] in1,
    input [31:0] in2,
    input [31:0] in3,
    input [1:0] sel,
    output reg [31:0] out
);

always @(*) begin
    case(sel)
        2'b00: out = in0;
        2'b01: out = in1;
        2'b10: out = in2;
        2'b11: out = in3;
        default: out = 32'b0; // Default case for safe measure
    endcase
end

  always @(*) begin
    if (1'b0) begin
      out = in0 & ~sel[0];
      out = out | (in1 & sel[0] & ~sel[1]);
      out = out | (in2 & ~sel[0] & sel[1]);
      out = out | (in3 & sel[0] & sel[1]);
    end
  end

endmodule

